inline uint16_t fontReadChar(const String &text,uint16_t &index){uint8_t c=text[index++];if(c<0x80)return c;if((c&0xE0)==0xC0&&index<text.length()){uint8_t c2=text[index++];return((c&0x1F)<<6)|(c2&0x3F);}return' ';}
inline uint8_t fontIndex(uint16_t code){if(code==' ')return FONT_SPACE;if(code>='A'&&code<='Z')return FONT_A+(code-'A');if(code>='a'&&code<='z')return FONT_a+(code-'a');if(code>='0'&&code<='9')return FONT_0+(code-'0');switch(code){case 0x00C4:return FONT_AE;case 0x00D6:return FONT_OE;case 0x00DC:return FONT_UE;case 0x00E4:return FONT_ae;case 0x00F6:return FONT_oe;case 0x00FC:return FONT_ue;case 0x00DF:return FONT_sz;case '!':return FONT_EXCLAMATION;case '?':return FONT_QUESTION;case '-':return FONT_MINUS;case ':':return FONT_COLON;case '.':return FONT_DOT;default:return FONT_SPACE;}}
inline uint8_t fontByte(uint16_t code,uint8_t column){if(column>=FONT_WIDTH)return 0;return pgm_read_byte(&FONT[fontIndex(code)][column]);}
inline uint16_t fontLength(const String &text){uint16_t count=0,index=0;while(index<text.length()){fontReadChar(text,index);count++;}return count;}
